import { useEffect, useState } from 'react'
import { createPortal } from 'react-dom'
import PropTypes from 'prop-types'
import { ControlPosition } from 'azure-maps-control'

import useMap from '../../shared/hooks/useMap'
import AzureCustomControl from './AzureCustomControl'

export default function CustomControl({ children, position }) {
  const [customControl, setCustomControl] = useState()
  const { map } = useMap()

  useEffect(() => {
    if (!map) {
      return undefined
    }

    const azureCustomControl = new AzureCustomControl()

    setCustomControl(azureCustomControl)

    map.controls.add(azureCustomControl, {
      position,
    })

    return () => {
      map.controls.remove(azureCustomControl)
      setCustomControl(undefined)
    }
  }, [map, position])

  if (!customControl?.container) {
    return null
  }

  return createPortal(children, customControl.container)
}

CustomControl.propTypes = {
  children: PropTypes.node.isRequired,
  position: PropTypes.oneOf(Object.values(ControlPosition)).isRequired,
}
