// Important is required here due to built in styles that set the cursor on child elements.
const draggingCursorClassName = css`
  &,
  & * {
    cursor: grabbing !important;
  }
`

const LARGEST_MARKER_SIZE_PX = 64
const BOUNDS_CHANGED_THROTTLE_DELAY_MS = 300
const ZOOM_DURATION_MS = 300
const ZOOM_TYPE = 'ease'
const SCROLL_INSTRUCTIONS_TIMEOUT_MS = 2000
const DOUBLE_CLICK_DELAY = 250
const MAP_VIEW_FITTING_DEBOUNCE_DELAY_MS = 100

function normalizeZoomLevels({ bounds, minZoom, maxZoom }) {
  // Ensure minZoom is always less than maxZoom
  // Subtract one to match Azure Maps zoom levels with Google Maps.
  let normalizedMinZoom = typeof maxZoom === 'number' ? minZoom - 1 : minZoom
  let normalizedMaxZoom = typeof maxZoom === 'number' ? maxZoom - 1 : maxZoom

  if (bounds) {
    normalizedMinZoom = null
    normalizedMaxZoom = null
  }

  if (typeof minZoom === 'number' && typeof maxZoom === 'number' && minZoom >= maxZoom) {
    normalizedMinZoom = maxZoom - 1
    normalizedMaxZoom = maxZoom
  }

  if (normalizedMinZoom <= 0) {
    normalizedMinZoom = 1
  }

  if (normalizedMaxZoom > 17) {
    normalizedMaxZoom = 17
  }

  return { normalizedMinZoom, normalizedMaxZoom }
}

function createTouchHandlers({ mapContainer, canvasElement, setShowScrollInstructions }) {
  let scrollInstructionsTimeout
  let isTouchstart = false
  let pageX = 0
  let pageY = 0
  let scale = 1

  const touchstartHandler = (event) => {
    // If two or more fingers, focus the canvas so it can receive pan events
    if (event.touches.length > 1) {
      clearTimeout(scrollInstructionsTimeout)
      setShowScrollInstructions(false)
      isTouchstart = false

      // Focus the canvas so it can receive the pan events
      if (canvasElement && document.activeElement !== canvasElement) {
        canvasElement.focus()
      }

      return
    }

    // Single finger handling
    clearTimeout(scrollInstructionsTimeout)
    pageX = event.changedTouches[0].pageX
    pageY = event.changedTouches[0].pageY
    isTouchstart = true

    scrollInstructionsTimeout = setTimeout(() => {
      if (!isTouchstart) {
        setShowScrollInstructions(false)
      }
    }, SCROLL_INSTRUCTIONS_TIMEOUT_MS)
  }

  const touchmoveHandler = (event) => {
    // Check if a second finger was added during move
    if (event.touches.length > 1 && isTouchstart) {
      // Transition from single-finger to two-finger mode
      isTouchstart = false
      clearTimeout(scrollInstructionsTimeout)
      setShowScrollInstructions(false)

      // Focus the canvas so it can receive the pan events
      if (canvasElement && document.activeElement !== canvasElement) {
        canvasElement.focus()
      }

      return
    }

    if (event.touches.length > 1) {
      // Two or more fingers - let Azure Maps handle it
      return
    }

    if (isTouchstart && event.touches.length === 1) {
      // Single finger in scroll mode
      setShowScrollInstructions(true)

      // Block Azure Maps from panning
      event.preventDefault()
      event.stopPropagation()

      const px = pageX - event.changedTouches[0].clientX
      const py = pageY - event.changedTouches[0].clientY

      if (scale === event.scale) {
        event.stopImmediatePropagation()
      }

      scale = event.scale

      // Find the scrollable parent container (could be window or an overlay)
      let scrollableParent = mapContainer
      while (scrollableParent && scrollableParent !== document.body) {
        const computedStyle = window.getComputedStyle(scrollableParent)
        const overflow = computedStyle.overflow
        const overflowY = computedStyle.overflowY
        const isScrollable =
          overflow === 'auto' || overflow === 'scroll' || overflowY === 'auto' || overflowY === 'scroll'

        // Check if element is actually scrollable (has overflow content)
        if (isScrollable && scrollableParent.scrollHeight > scrollableParent.clientHeight) {
          break
        }

        // Also check if element has a data-scrollable attribute (common in UI frameworks)
        if ('scrollable' in scrollableParent.dataset) {
          break
        }

        scrollableParent = scrollableParent.parentElement
      }

      // If no scrollable parent found, use window
      if (!scrollableParent || scrollableParent === document.body) {
        if (window.scrollY === 0) {
          window.parent.scrollBy(px, py)
        } else {
          window.scrollTo(px, py)
        }
      } else {
        // Scroll the container element
        scrollableParent.scrollBy(px, py)
      }
    }
  }

  const touchendHandler = (event) => {
    clearTimeout(scrollInstructionsTimeout)

    // Check remaining touches
    const remainingTouches = event.touches.length

    if (remainingTouches === 0) {
      // All fingers lifted
      isTouchstart = false

      scrollInstructionsTimeout = setTimeout(() => {
        setShowScrollInstructions(false)
      }, SCROLL_INSTRUCTIONS_TIMEOUT_MS)
    } else if (remainingTouches === 1 && !isTouchstart) {
      // Down to one finger from two - don't switch to scroll mode yet
      // Wait until all fingers are lifted
    }
  }

  const cleanup = () => {
    clearTimeout(scrollInstructionsTimeout)
  }

  return { touchstartHandler, touchmoveHandler, touchendHandler, cleanup }
}

function createWheelHandler({ ctrlKeydownRef, nonInteractiveRef, parentScrollsRef, setShowScrollInstructions }) {
  let scrollInstructionsTimeout

  return () => {
    if (!nonInteractiveRef.current && parentScrollsRef.current && !ctrlKeydownRef.current) {
      setShowScrollInstructions(true)

      clearTimeout(scrollInstructionsTimeout)
      scrollInstructionsTimeout = setTimeout(() => {
        setShowScrollInstructions(false)
      }, SCROLL_INSTRUCTIONS_TIMEOUT_MS)
    }
  }
}

function createMapOptions({
  bounds,
  initialLatitude,
  initialLongitude,
  initialZoom,
  maxZoom,
  minZoom,
  nonInteractive,
  parentScrolls,
}) {
  // Minus one to match the Azure Maps zoom level with Google Maps.
  const normalizedInitialZoom = initialZoom ? initialZoom - 1 : undefined

  const { normalizedMinZoom, normalizedMaxZoom } = normalizeZoomLevels({ bounds, minZoom, maxZoom })

  let center = [initialLongitude, initialLatitude]

  let boundingBox
  if (bounds?.north) {
    boundingBox = BoundingBox.fromEdges(bounds.west, bounds.south, bounds.east, bounds.north)
    center = BoundingBox.getCenter(boundingBox)
  }

  return {
    center,
    dragPanInteraction: !nonInteractive,
    duration: ZOOM_DURATION_MS,
    interactive: !nonInteractive,
    maxBounds: boundingBox,
    maxZoom: normalizedMaxZoom,
    minZoom: normalizedMinZoom,
    scrollZoomInteraction: !(nonInteractive || parentScrolls),
    type: ZOOM_TYPE,
    zoom: normalizedInitialZoom,
  }
}

function addTouchEventListeners({ touchHandlers, canvasElement }) {
  // Add listeners to canvas with capture phase to intercept before Azure Maps
  canvasElement.addEventListener('touchstart', touchHandlers.touchstartHandler, { passive: false, capture: true })
  canvasElement.addEventListener('touchmove', touchHandlers.touchmoveHandler, { passive: false, capture: true })
  canvasElement.addEventListener('touchend', touchHandlers.touchendHandler, { passive: false, capture: true })
}

function addMouseEventListeners({ newMap, nonInteractiveRef, wheelListener }) {
  newMap.events.add('wheel', wheelListener)

  const mapContainer = newMap.getCanvasContainer()

  newMap.events.add('mousedown', () => {
    if (!nonInteractiveRef.current) {
      mapContainer.classList.add(draggingCursorClassName)
    }
  })

  newMap.events.add('mouseup', () => {
    mapContainer.classList.remove(draggingCursorClassName)
  })

  return { wheelListener }
}

async function handleMapReady({
  azureSubscriptionKey,
  ctrlKeydownRef,
  initialOptionsRef,
  isPrimarilyTouchscreen,
  mapRef,
  nonInteractiveRef,
  onClick,
  parentScrollsRef,
  setLoading,
  setMap,
  setShowScrollInstructions,
  sharedPopperRef,
}) {
  const onChange = initialOptionsRef.current.onChange
  const onReady = initialOptionsRef.current.onReady

  const newMap = new azure.Map(mapRef.current, {
    ...initialOptionsRef.current.mapOptions,
    authOptions: {
      authType: 'subscriptionKey',
      subscriptionKey: azureSubscriptionKey,
    },
    language: i18n.language,
    progressiveLoading: true,
    showFeedbackLink: false,
    view: 'Auto',
  })

  if (!initialOptionsRef.current.mapOptions.interactive) {
    newMap.getCanvasContainer().style.cursor = 'default'
  } else {
    newMap.getCanvasContainer().style.cursor = onClick ? 'pointer' : 'grab'
  }

  await createAllSprites({ map: newMap })

  let touchHandlers
  let mouseListeners

  const canvasElementHolder = { element: null }

  const loadHandler = () => {
    setLoading(false)
    setMap(newMap)

    // Handle touch device scrolling when clicking on the map
    // https://samples.azuremaps.com/?sample=limit-map-to-two-finger-panning --> Limit Map to Two Finger Panning
    if (isPrimarilyTouchscreen) {
      canvasElementHolder.element = newMap.getCanvasContainer().querySelector('.atlas-map-canvas')

      touchHandlers = createTouchHandlers({
        mapContainer: mapRef.current,
        canvasElement: canvasElementHolder.element,
        setShowScrollInstructions,
      })

      addTouchEventListeners({ touchHandlers, canvasElement: canvasElementHolder.element })
    } else {
      const wheelListener = createWheelHandler({
        ctrlKeydownRef,
        nonInteractiveRef,
        parentScrollsRef,
        setShowScrollInstructions,
      })

      mouseListeners = addMouseEventListeners({ newMap, nonInteractiveRef, wheelListener })
    }

    onChange?.({ closeOverlay: () => sharedPopperRef.current?.closeOverlay?.() })
    onReady?.()
  }

  newMap.events.addOnce('load', loadHandler)

  return { canvasElement: canvasElementHolder, mouseListeners, newMap, touchHandlers }
}

function cleanupEventListeners({ canvasElement, mouseListeners, newMap, touchHandlers }) {
  if (touchHandlers && canvasElement?.element) {
    canvasElement.element.removeEventListener('touchstart', touchHandlers.touchstartHandler, { capture: true })
    canvasElement.element.removeEventListener('touchmove', touchHandlers.touchmoveHandler, { capture: true })
    canvasElement.element.removeEventListener('touchend', touchHandlers.touchendHandler, { capture: true })
    touchHandlers.cleanup()
  }

  if (mouseListeners?.wheelListener && newMap) {
    newMap.events.remove('wheel', mouseListeners.wheelListener)
  }
}

function useMapCreation({
  azureSubscriptionKey,
  bounds,
  ctrlKeydownRef,
  initialLatitude,
  initialLongitude,
  initialZoom,
  isPrimarilyTouchscreen,
  mapRef,
  maxZoom,
  minZoom,
  nonInteractive,
  nonInteractiveRef,
  onChange,
  onClick,
  onReady,
  parentScrolls,
  parentScrollsRef,
  setLoading,
  setMap,
  setShowScrollInstructions,
  sharedPopperRef,
}) {
  const mapCreatedRef = useRef()
  const initialOptionsRef = useRef()
  const newMapRef = useRef()
  const touchHandlersRef = useRef()
  const mouseListenersRef = useRef()
  const canvasElementRef = useRef()

  if (!initialOptionsRef.current) {
    initialOptionsRef.current = {
      mapOptions: createMapOptions({
        bounds,
        initialLatitude,
        initialLongitude,
        initialZoom,
        maxZoom,
        minZoom,
        nonInteractive,
        parentScrolls,
      }),
      onChange,
      onReady,
    }
  }

  // Create the map
  useEffect(() => {
    if (mapRef.current && !mapCreatedRef.current) {
      mapCreatedRef.current = true
      setLoading(true)

      handleMapReady({
        azureSubscriptionKey,
        ctrlKeydownRef,
        initialOptionsRef,
        isPrimarilyTouchscreen,
        mapRef,
        nonInteractiveRef,
        onClick,
        parentScrollsRef,
        setLoading,
        setMap,
        setShowScrollInstructions,
        sharedPopperRef,
      }).then((mapHandlers) => {
        newMapRef.current = mapHandlers.newMap
        touchHandlersRef.current = mapHandlers.touchHandlers
        mouseListenersRef.current = mapHandlers.mouseListeners
        canvasElementRef.current = mapHandlers.canvasElement
      })
    }

    return () => {
      if (newMapRef.current) {
        cleanupEventListeners({
          canvasElement: canvasElementRef.current,
          mouseListeners: mouseListenersRef.current,
          newMap: newMapRef.current,
          touchHandlers: touchHandlersRef.current,
        })

        newMapRef.current = undefined
        touchHandlersRef.current = undefined
        mouseListenersRef.current = undefined
        canvasElementRef.current = undefined
      }
    }
  }, [
    azureSubscriptionKey,
    ctrlKeydownRef,
    isPrimarilyTouchscreen,
    mapRef,
    nonInteractiveRef,
    onClick,
    onReady,
    parentScrollsRef,
    setLoading,
    setMap,
    setShowScrollInstructions,
    sharedPopperRef,
  ])
}

function useBoundsChangedListener({ map, onBoundsChanged, onBoundsChangedCallbacksRef }) {
  const boundsChanged = useCallback(() => {
    if (!map) return

    const camera = map.getCamera()
    const currentCenter = camera.center
    const currentBounds = camera.bounds
    const currentZoom = camera.zoom + 1 // Add one to match Azure Maps zoom levels with Google Maps.

    const west = currentBounds[0]
    const south = currentBounds[1]
    const east = currentBounds[2]
    const north = currentBounds[3]

    const args = {
      center: { latitude: currentCenter[1], longitude: currentCenter[0] },
      east,
      north,
      south,
      west,
      zoom: currentZoom,
    }

    onBoundsChangedCallbacksRef.current.forEach(({ callback }) => callback(args))
    onBoundsChanged?.(args)
  }, [map, onBoundsChanged, onBoundsChangedCallbacksRef])

  const throttledBoundsChanged = useThrottle(BOUNDS_CHANGED_THROTTLE_DELAY_MS, boundsChanged)

  // Listen for bounds changes
  useEffect(() => {
    if (map && (typeof onBoundsChanged === 'function' || onBoundsChangedCallbacksRef.current.length > 0)) {
      map.events.add('render', throttledBoundsChanged)
    }

    return () => {
      map?.events.remove('render', throttledBoundsChanged)
    }
  }, [map, onBoundsChanged, onBoundsChangedCallbacksRef, throttledBoundsChanged])
}

function useZoomChangedListener({ map, onZoomChangedCallbacksRef }) {
  const previousZoomRef = useRef(null)

  const zoomChanged = useCallback(() => {
    if (!map || onZoomChangedCallbacksRef.current.length === 0) {
      return
    }

    const camera = map.getCamera()

    const currentZoom = camera.zoom

    // Only proceed if the zoom level has actually changed
    if (previousZoomRef.current !== null && previousZoomRef.current === currentZoom) {
      return
    }

    // Update the previous zoom reference
    previousZoomRef.current = currentZoom

    const currentCenter = camera.center
    const currentBounds = camera.bounds

    const west = currentBounds[0]
    const south = currentBounds[1]
    const east = currentBounds[2]
    const north = currentBounds[3]

    const args = {
      center: { latitude: currentCenter[1], longitude: currentCenter[0] },
      east,
      north,
      south,
      west,
      zoom: currentZoom,
    }

    onZoomChangedCallbacksRef.current.forEach(({ callback }) => callback(args))
  }, [map, onZoomChangedCallbacksRef])

  // Listen for zoom changes
  useEffect(() => {
    if (map) {
      // Initialize the previous zoom value when setting up the listener
      const camera = map.getCamera()
      previousZoomRef.current = camera.zoom

      map.events.add('zoomend', zoomChanged)
    }

    return () => {
      map?.events.remove('zoomend', zoomChanged)
    }
  }, [map, onZoomChangedCallbacksRef, zoomChanged])
}

function useMapClickListener({ map, onClick, skipNextClickRef }) {
  const onClickRef = useRef(onClick)
  const clickTimerRef = useRef(null)
  const isDoubleClickRef = useRef(false)

  useEffect(() => {
    onClickRef.current = onClick
  }, [onClick])

  useEffect(() => {
    if (!map) {
      return undefined
    }

    // Ignore double clicks
    const doubleClickHandler = () => {
      // Set flag to prevent single click from firing
      isDoubleClickRef.current = true

      // Clear any pending single click
      if (clickTimerRef.current) {
        clearTimeout(clickTimerRef.current)
        clickTimerRef.current = null
      }

      // Reset flag after delay
      setTimeout(() => {
        isDoubleClickRef.current = false
      }, DOUBLE_CLICK_DELAY)
    }

    const clickHandler = (event) => {
      if (skipNextClickRef.current) {
        skipNextClickRef.current = false
        return
      }

      // Don't process click if we're in a double-click sequence
      if (isDoubleClickRef.current) {
        return
      }

      // Delay single click to wait for potential double click
      clickTimerRef.current = setTimeout(() => {
        if (onClickRef.current && !isDoubleClickRef.current) {
          onClickRef.current({
            position: {
              latitude: event.position[1],
              longitude: event.position[0],
            },
          })
        }

        clickTimerRef.current = null
      }, DOUBLE_CLICK_DELAY)
    }

    map.events.add('click', clickHandler)
    map.events.add('dblclick', doubleClickHandler)

    return () => {
      if (clickTimerRef.current) {
        clearTimeout(clickTimerRef.current)
      }

      map.events.remove('click', clickHandler)
      map.events.remove('dblclick', doubleClickHandler)
    }
  }, [map, skipNextClickRef])
}

function useMapOptions({ map, nonInteractive, nonInteractiveRef, onClick, options, parentScrolls, parentScrollsRef }) {
  const previousOptionsRef = useRef()

  // Update the map options when they change
  useEffect(() => {
    if (map) {
      const updatedOptions = {
        duration: ZOOM_DURATION_MS,
        maxZoom: options.maxZoom,
        minZoom: options.minZoom,
        type: ZOOM_TYPE,
        zoom: options.zoom,
      }

      if (options.maxBounds) {
        updatedOptions.maxBounds = options.maxBounds
      } else {
        updatedOptions.maxBounds = undefined
      }

      // Only call setCamera if the options have actually changed
      const previousOptions = previousOptionsRef.current
      const hasOptionsChanged =
        !previousOptions ||
        previousOptions.maxZoom !== updatedOptions.maxZoom ||
        previousOptions.minZoom !== updatedOptions.minZoom ||
        previousOptions.zoom !== updatedOptions.zoom ||
        previousOptions.maxBounds !== updatedOptions.maxBounds

      nonInteractiveRef.current = nonInteractive
      parentScrollsRef.current = parentScrolls

      if (hasOptionsChanged) {
        map.setCamera(updatedOptions)
        previousOptionsRef.current = updatedOptions
      }

      map.setUserInteraction({
        interactive: !nonInteractive,
        scrollZoomInteraction: !(nonInteractive || parentScrolls),
      })

      if (nonInteractive) {
        map.getCanvasContainer().style.cursor = 'default'
      } else {
        map.getCanvasContainer().style.cursor = onClick ? 'pointer' : 'grab'
      }
    }
  }, [map, nonInteractive, nonInteractiveRef, onClick, options, parentScrolls, parentScrollsRef])
}

function useMapViewFitting({ childrenBounds, childrenBoundsApi, map, options }) {
  // Fit the map to the children bounds or center on the initial location
  useEffect(() => {
    if (!map) {
      return undefined
    }

    if (childrenBoundsApi.skipNextFitToChildrenRef.current) {
      childrenBoundsApi.skipNextFitToChildrenRef.current = false
      return undefined
    }

    // Debounce setCamera calls to prevent multiple rapid updates during initial render
    const timeoutId = setTimeout(() => {
      if (childrenBounds.bounds) {
        // We may want to consider only running this if the user has
        // not changed the map bounds from the initial bounds.
        const boundingBox = BoundingBox.fromEdges(
          childrenBounds.bounds.west,
          childrenBounds.bounds.south,
          childrenBounds.bounds.east,
          childrenBounds.bounds.north
        )

        map.setCamera({
          bounds: boundingBox,
          duration: ZOOM_DURATION_MS,
          maxBounds: map.getCamera().maxBounds,
          padding: LARGEST_MARKER_SIZE_PX,
          type: ZOOM_TYPE,
        })
      } else if (childrenBounds.optimalZoom !== undefined && childrenBounds.centroidLocation) {
        map.setCamera({
          center: [childrenBounds.centroidLocation.longitude, childrenBounds.centroidLocation.latitude],
          duration: ZOOM_DURATION_MS,
          type: ZOOM_TYPE,
          zoom: childrenBounds.optimalZoom,
        })
      } else {
        map.setCamera({
          center: options.center,
          duration: ZOOM_DURATION_MS,
          type: ZOOM_TYPE,
          zoom: options.zoom,
        })
      }
    }, MAP_VIEW_FITTING_DEBOUNCE_DELAY_MS)

    return () => {
      clearTimeout(timeoutId)
    }
  }, [childrenBounds, childrenBoundsApi, map, options])
}

function useScrollZoomInteraction({ ctrlKeydownRef, map, nonInteractive, parentScrolls, setShowScrollInstructions }) {
  // Setup scroll zoom interaction
  // Note: In certain situations the zoom interactions may stop working.
  // Quickly pressing and releasing the ctrl key while scroll-zooming
  // will cause the scroll zoom to stop working.
  // This appears to be a bug in Azure Maps as it happens in their examples as well.
  // See: https://samples.azuremaps.com/map/limit-scroll-wheel-zoom
  useEffect(() => {
    if (!map) return undefined

    function keydownListener({ ctrlKey }) {
      if (ctrlKey) {
        ctrlKeydownRef.current = true
        setShowScrollInstructions(false)
        map.setUserInteraction({ scrollZoomInteraction: true })
      }
    }
    function keyupListener({ ctrlKey }) {
      if (!ctrlKey) {
        ctrlKeydownRef.current = false
        map.setUserInteraction({ scrollZoomInteraction: !(nonInteractive || parentScrolls) })
      }
    }

    window.parent.addEventListener('keydown', keydownListener)
    window.parent.addEventListener('keyup', keyupListener)
    window.addEventListener('keydown', keydownListener)
    window.addEventListener('keyup', keyupListener)

    return () => {
      window.parent.removeEventListener('keydown', keydownListener)
      window.parent.removeEventListener('keyup', keyupListener)
      window.removeEventListener('keydown', keydownListener)
      window.removeEventListener('keyup', keyupListener)
    }
  }, [map, nonInteractive, parentScrolls, ctrlKeydownRef, setShowScrollInstructions])
}

function useMapIdleState({ map, isIdle }) {
  useEffect(() => {
    if (!map) {
      return undefined
    }

    function handleIdle() {
      isIdle.current = true
    }

    function handleNotIdle() {
      isIdle.current = false
    }

    map.events.add('idle', handleIdle)
    map.events.add('movestart', handleNotIdle)
    map.events.add('zoomstart', handleNotIdle)

    return () => {
      map.events.remove('idle', handleIdle)
      map.events.remove('movestart', handleNotIdle)
      map.events.remove('zoomstart', handleNotIdle)
    }
  }, [map, isIdle])
}

const AzureMap = forwardRef(
  (
    {
      azureSubscriptionKey,
      bounds,
      children,
      hideFullscreenControl,
      hideMapTypeControl,
      initialLatitude,
      initialLongitude,
      initialMapTypeId,
      initialZoom,
      maxZoom,
      minZoom,
      nonInteractive,
      onBoundsChanged,
      onChange,
      onClick,
      onInfoClosed,
      onReady,
      parentScrolls,
      testId = 'azure-map',
      userLocation,
    },
    ref
  ) => {
    const mapRef = useRef()
    const [map, setMap] = useState()
    const [loading, setLoading] = useState(true)
    const childrenBounds = useChildrenBounds()
    const childrenBoundsApi = useChildrenBoundsApi()
    const [showScrollInstructions, setShowScrollInstructions] = useState(false)
    const ctrlKeydownRef = useRef(false)
    const onBoundsChangedCallbacksRef = useRef([])
    const onZoomChangedCallbacksRef = useRef([])
    const fullscreenContainerRef = useRef()
    const nonInteractiveRef = useRef(nonInteractive)
    const parentScrollsRef = useRef(parentScrolls)
    const isIdle = useRef(true)
    const sharedPopperRef = useRef()
    const skipNextClickRef = useRef(false)

    useImperativeHandle(
      ref,
      () => ({
        closeOverlay: () => sharedPopperRef.current?.closeOverlay?.(),
      }),
      []
    )

    const isPrimarilyTouchscreen = typeof window !== 'undefined' && window.matchMedia('(pointer: coarse)').matches

    // Ensure deterministic (re)insertion order for controls when interactivity toggles.
    const orderedControlsKey = useMemo(
      () => `orderedControls:${nonInteractive ? 'nonInteractive' : 'interactive'}`,
      [nonInteractive]
    )

    const options = useMemo(
      () =>
        createMapOptions({
          bounds,
          initialLatitude,
          initialLongitude,
          initialZoom,
          maxZoom,
          minZoom,
          nonInteractive,
          parentScrolls,
        }),
      [bounds, initialLatitude, initialLongitude, initialZoom, maxZoom, minZoom, nonInteractive, parentScrolls]
    )

    useMapCreation({
      azureSubscriptionKey,
      bounds,
      ctrlKeydownRef,
      initialLatitude,
      initialLongitude,
      initialZoom,
      isPrimarilyTouchscreen,
      mapRef,
      maxZoom,
      minZoom,
      nonInteractive,
      nonInteractiveRef,
      onChange,
      onClick,
      onReady,
      parentScrolls,
      parentScrollsRef,
      setLoading,
      setMap,
      setShowScrollInstructions,
      sharedPopperRef,
    })

    useBoundsChangedListener({ map, onBoundsChanged, onBoundsChangedCallbacksRef })
    useZoomChangedListener({ map, onZoomChangedCallbacksRef })
    useMapClickListener({ map, onClick, skipNextClickRef })
    // NOTE: This must come before `useMapViewFitting` in order for the children bounds to work correctly.
    useMapOptions({
      map,
      nonInteractive,
      nonInteractiveRef,
      onClick,
      options,
      parentScrolls,
      parentScrollsRef,
    })
    // NOTE: This must come after `useMapOptions` in order for the options to be set correctly.
    useMapViewFitting({ childrenBounds, childrenBoundsApi, map, options })
    useScrollZoomInteraction({ ctrlKeydownRef, map, nonInteractive, parentScrolls, setShowScrollInstructions })
    useMapIdleState({ map, isIdle })

    const getCurrentZoom = useCallback(() => {
      if (!map) {
        return null
      }

      const camera = map.getCamera()

      const currentZoom = camera.zoom + 1 // Add one to match Azure Maps zoom levels with Google Maps.

      return currentZoom
    }, [map])

    const onBoundsChangedAdd = useCallback(
      ({ callback, id }) => {
        onBoundsChangedCallbacksRef.current.push({ callback, id })

        if (map) {
          const camera = map.getCamera()
          const currentCenter = camera.center
          const currentBounds = camera.bounds
          const currentZoom = camera.zoom + 1 // Add one to match Azure Maps zoom levels with Google Maps.

          const west = currentBounds[0]
          const south = currentBounds[1]
          const east = currentBounds[2]
          const north = currentBounds[3]

          callback({
            center: { latitude: currentCenter[1], longitude: currentCenter[0] },
            east,
            north,
            south,
            west,
            zoom: currentZoom,
          })
        }
      },
      [map]
    )

    const onBoundsChangedRemove = useCallback(({ id }) => {
      onBoundsChangedCallbacksRef.current = onBoundsChangedCallbacksRef.current.filter(
        ({ id: currentId }) => currentId !== id
      )
    }, [])

    const onBoundsChangedMemo = useMemo(
      () => ({
        add: onBoundsChangedAdd,
        remove: onBoundsChangedRemove,
      }),
      [onBoundsChangedAdd, onBoundsChangedRemove]
    )

    const onZoomChangedAdd = useCallback(({ callback, id }) => {
      onZoomChangedCallbacksRef.current.push({ callback, id })
    }, [])

    const onZoomChangedRemove = useCallback(({ id }) => {
      onZoomChangedCallbacksRef.current = onZoomChangedCallbacksRef.current.filter(
        ({ id: currentId }) => currentId !== id
      )
    }, [])

    const onZoomChangedMemo = useMemo(
      () => ({
        add: onZoomChangedAdd,
        remove: onZoomChangedRemove,
      }),
      [onZoomChangedAdd, onZoomChangedRemove]
    )

    const whenIdle = useCallback(
      ({ callback }) => {
        return new Promise((resolve) => {
          if (isIdle.current) {
            callback()
            resolve()
          } else if (map) {
            map.events.addOnce('idle', () => {
              callback()
              resolve()
            })
          }
        })
      },
      [map]
    )

    const zoomPan = useCallback(
      ({ bounds: zoomPanBounds, latitude, longitude, zoom }) => {
        if (!map) {
          return
        }

        const cameraOptions = {
          duration: ZOOM_DURATION_MS,
          type: ZOOM_TYPE,
        }

        let shouldSetCamera = false

        if (zoomPanBounds) {
          shouldSetCamera = true

          const boundingBox = BoundingBox.fromEdges(
            zoomPanBounds.west,
            zoomPanBounds.south,
            zoomPanBounds.east,
            zoomPanBounds.north
          )

          cameraOptions.bounds = boundingBox
          cameraOptions.padding = LARGEST_MARKER_SIZE_PX
        } else if (zoom) {
          shouldSetCamera = true

          cameraOptions.zoom = zoom
        }

        if (
          typeof latitude === 'number' &&
          !Number.isNaN(latitude) &&
          typeof longitude === 'number' &&
          !Number.isNaN(longitude)
        ) {
          shouldSetCamera = true

          cameraOptions.center = [longitude, latitude]
        }

        if (shouldSetCamera) {
          map.setCamera(cameraOptions)
        }
      },
      [map]
    )

    const updateHandlerAdd = useCallback(
      (callback) => {
        if (!map) {
          return
        }

        map.events.add('move', callback)
      },
      [map]
    )

    const updateHandlerRemove = useCallback(
      (callback) => {
        if (!map) {
          return
        }

        map.events.remove('move', callback)
      },
      [map]
    )

    const updateHandlerMemo = useMemo(
      () => ({
        add: updateHandlerAdd,
        remove: updateHandlerRemove,
      }),
      [updateHandlerAdd, updateHandlerRemove]
    )

    return (
      <div className={mapContainerClassName} ref={fullscreenContainerRef}>
        {loading && (
          <Center>
            <NoticeLoading color={rawDayColors.gray[100]} size="lg" />
          </Center>
        )}
        <div className={mapClassName} data-testid={testId} ref={mapRef} />
        <div className={cx(scrollClassName, showScrollInstructions && scrollShowClassName)}>
          {isPrimarilyTouchscreen
            ? i18n.t('map.map.touch', 'Use two fingers to move the map')
            : i18n.t('map.map.scroll', 'Use ctrl + scroll to zoom in and out.')}
        </div>
        <MapProvider
          azure
          fullscreenContainer={fullscreenContainerRef.current}
          getCurrentZoom={getCurrentZoom}
          initialLatitude={initialLatitude}
          initialLongitude={initialLongitude}
          initialZoom={initialZoom}
          map={map}
          mapContainer={mapRef}
          maxZoom={options.maxZoom} // Contains the normalized max zoom level
          nonInteractive={nonInteractive}
          onBoundsChanged={onBoundsChangedMemo}
          onZoomChanged={onZoomChangedMemo}
          skipNextClickRef={skipNextClickRef}
          whenIdle={whenIdle}
          zoomPan={zoomPan}
        >
          <SharedPopperProvider onInfoClosed={onInfoClosed} updateHandler={updateHandlerMemo} ref={sharedPopperRef}>
            {userLocation && <UserLocationControl />}
            <ResetViewControl />
            {children}
          </SharedPopperProvider>
          <Fragment key={orderedControlsKey}>
            <ZoomControl />
            {!hideFullscreenControl && !isPrimarilyTouchscreen && <FullscreenControl />}
          </Fragment>
          {!hideMapTypeControl && <MapTypeControl initialMapTypeId={initialMapTypeId} />}
        </MapProvider>
      </div>
    )
  }
)

AzureMap.displayName = 'AzureMap'

export default AzureMap

AzureMap.propTypes = {
  azureSubscriptionKey: PropTypes.string,
  bounds: PropTypes.shape({
    east: PropTypes.number.isRequired,
    north: PropTypes.number.isRequired,
    south: PropTypes.number.isRequired,
    west: PropTypes.number.isRequired,
  }),
  children: PropTypes.node,
  hideFullscreenControl: PropTypes.bool,
  hideMapTypeControl: PropTypes.bool,
  initialLatitude: PropTypes.number.isRequired,
  initialLongitude: PropTypes.number.isRequired,
  initialMapTypeId: PropTypes.string,
  initialZoom: PropTypes.number,
  maxZoom: PropTypes.number,
  minZoom: PropTypes.number,
  nonInteractive: PropTypes.bool,
  onBoundsChanged: PropTypes.func,
  onChange: PropTypes.func,
  onClick: PropTypes.func,
  onInfoClosed: PropTypes.func,
  onReady: PropTypes.func,
  parentScrolls: PropTypes.bool,
  testId: PropTypes.string,
  userLocation: PropTypes.bool,
}
