import pathColors from '../../shared/Path/colors'
import markerConfig from '../../shared/Marker/config.json'

const CIRCLE_RADIUS = 5.5
const SQUARE_SIZE = 5.5
const SOLID_ARROW_HEIGHT = 18
const SOLID_ARROW_WIDTH = 12
const DASHED_ARROW_WING_SIZE = 7
function createSymbolSvg({ color, dashed, opacity, symbolType }) {
  const { line: stroke, symbol } = pathColors[color] || pathColors.red

  const fill = symbolType === 'arrow' ? stroke : symbol
  let symbolHeight = 24
  let symbolWidth = 24
  if (symbolType === 'teardrop') {
    symbolHeight = markerConfig.default.blockSize
    symbolWidth = markerConfig.default.inlineSize
  } else if (symbolType === 'arrow' && !dashed) {
    symbolHeight = SOLID_ARROW_HEIGHT
    symbolWidth = SOLID_ARROW_WIDTH
  } else if (symbolType === 'arrow' && dashed) {
    symbolHeight = DASHED_ARROW_WING_SIZE * 2
    symbolWidth = DASHED_ARROW_WING_SIZE * 2
  }

  const halfSymbolHeight = symbolHeight / 2
  const halfSymbolWidth = symbolWidth / 2

  let path = `M0 0 m-${CIRCLE_RADIUS},0 a${CIRCLE_RADIUS},${CIRCLE_RADIUS} 0 1,0 ${CIRCLE_RADIUS * 2},0 a${CIRCLE_RADIUS},${CIRCLE_RADIUS} 0 1,0 -${CIRCLE_RADIUS * 2},0` // circle
  let strokeWidth = 0
  let transform = `translate(${halfSymbolWidth}, ${halfSymbolHeight}) `

  if (symbolType === 'square') {
    path = `M -${SQUARE_SIZE},-${SQUARE_SIZE} L ${SQUARE_SIZE},-${SQUARE_SIZE} L ${SQUARE_SIZE},${SQUARE_SIZE} L -${SQUARE_SIZE},${SQUARE_SIZE} Z`
  } else if (symbolType === 'teardrop') {
    path = markerConfig.default.path
    transform = `translate(5,8) scale(0.75)`
  } else if (symbolType === 'arrow' && dashed) {
    path = `M${DASHED_ARROW_WING_SIZE} ${DASHED_ARROW_WING_SIZE} L${DASHED_ARROW_WING_SIZE * 2} ${DASHED_ARROW_WING_SIZE * 2} M${DASHED_ARROW_WING_SIZE} ${DASHED_ARROW_WING_SIZE} L1 ${DASHED_ARROW_WING_SIZE * 2}`
    strokeWidth = 2
    transform = ''
  } else if (symbolType === 'arrow' && !dashed) {
    path = `M${SOLID_ARROW_WIDTH / 2} 1 L${SOLID_ARROW_WIDTH} ${SOLID_ARROW_HEIGHT} L0 ${SOLID_ARROW_HEIGHT} Z`
    transform = ''
  }

  const svgContent = `<svg 
    height="${symbolHeight}"
    viewBox="0 0 ${symbolWidth} ${symbolHeight}"
    width="${symbolWidth}"
    xmlns="http://www.w3.org/2000/svg" 
  >
    <path 
      d="${path}"
      fill="${fill}"
      fill-opacity="${opacity}"
      stroke="${stroke}"
      stroke-opacity="${opacity}"
      stroke-width="${strokeWidth}"
      transform="${transform}"
    />
  </svg>`

  const encodedSvg = encodeURIComponent(svgContent)

  return `data:image/svg+xml;charset=UTF-8,${encodedSvg}`
}

export function createAllSprites({ map }) {
  const symbolNames = ['arrow-dashed', 'arrow', 'circle', 'square', 'teardrop']
  const colorsNames = Object.keys(pathColors)

  const promises = []
  symbolNames.forEach((symbolName) => {
    colorsNames.forEach((colorName) => {
      const iconId = `${symbolName}-${colorName}`
      if (!map.imageSprite.hasImage(iconId)) {
        promises.push(
          map.imageSprite.add(
            iconId,
            createSymbolSvg({
              color: colorName,
              dashed: symbolName === 'arrow-dashed',
              symbolType: symbolName.includes('arrow') ? 'arrow' : symbolName,
            })
          )
        )
      }
    })
  })

  return Promise.all(promises)
}
