import { useCallback, useEffect, useRef } from 'react'

/**
 * Creates a leading & trailing throttle implementation
 *
 * @param {number} delay ms delay to schedule the throttled callback
 * @param {function(...*): void} callback
 * @returns {function(...*): void} a stable throttled function
 */
export default function useThrottle(delay, callback) {
  const timeoutRef = useRef(null)
  const lastCallbackTimeRef = useRef(0)
  const latestArgsRef = useRef([])

  const throttledCallback = useCallback(
    (...args) => {
      const now = Date.now()
      const timeSinceLastExecution = now - lastCallbackTimeRef.current
      latestArgsRef.current = args

      if (timeSinceLastExecution >= delay) {
        lastCallbackTimeRef.current = now
        callback(...latestArgsRef.current) // leading
      } else if (!timeoutRef.current) {
        const remainingTime = delay - timeSinceLastExecution
        timeoutRef.current = setTimeout(() => {
          lastCallbackTimeRef.current = Date.now()
          timeoutRef.current = null
          callback(...latestArgsRef.current) // trailing/throttled subsequent
        }, remainingTime)
      }
    },
    [callback, delay]
  )

  useEffect(() => {
    return () => {
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current)
      }
    }
  }, [])

  return throttledCallback
}
