import { css } from '@linaria/core'
import { rawDayColors } from '@fs/zion-ui/quarks-authorized-use-only'

// These styles allow us to replicate the look and feel of the Google Maps MapTypeControl
// without having to recreate the zion-ui component from scratch.  This way we get the
// benefits of the zion-ui component's accessibility and keyboard navigation features.
export default css`
  padding: 10px;
  pointer-events: none;

  > div {
    pointer-events: auto;
  }

  button {
    all: unset;
    background-color: ${rawDayColors.gray['00']};
    block-size: 40px;
    border: none;
    box-shadow: rgba(0, 0, 0, 0.3) 0px 1px 4px -1px;
    color: #666666;
    cursor: pointer;
    font-size: 18px;
    padding: 0 17px;
    position: relative;
    user-select: none;
    z-index: 3;

    &:focus-visible,
    &:focus:not(:focus-visible),
    &:active:not([aria-disabled='true']),
    &:hover:not([aria-disabled='true']):not(:active) {
      background-color: #ebebeb !important;
      color: #333333;
    }
  }

  &[data-selected-button-index='1'] > div:nth-of-type(1) button,
  &[data-selected-button-index='2'] > div:nth-of-type(2) button {
    font-weight: 500;
    color: black;
  }

  > div:nth-of-type(1) button {
    border-end-start-radius: 2px;
    border-start-start-radius: 2px;
  }

  > div:nth-of-type(2) button {
    border-end-end-radius: 2px;
    border-start-end-radius: 2px;
  }

  [data-popper-placement] {
    margin-block-start: -8px !important;

    span {
      font-size: 18px;
      white-space: nowrap;
    }

    [class*='elevationBaseCss'] {
      border-radius: 2px !important;

      > div {
        border-end-end-radius: 2px !important;
        border-end-start-radius: 2px !important;
        border-start-end-radius: 0px !important;
        border-start-start-radius: 0px !important;
      }
    }

    li:focus-visible [class*='innerContainerCss'][interactable]:not([aria-disabled='true']) {
      outline: auto 2px Highlight;
      outline: -webkit-focus-ring-color auto 1px;
      outline-offset: -2px;
    }

    [class*='innerContainerCss'] {
      block-size: 20px;
      min-block-size: initial;
      padding-block-end: 20px;
      padding-block-start: 20px;
      padding-inline-end: 10px;
      padding-inline-start: 20px;

      &[interactable]:not([aria-disabled='true']):focus-visible {
        outline: auto 2px Highlight;
        outline: -webkit-focus-ring-color auto 1px;
        outline-offset: -2px;
      }
    }

    [class*='sideCarCss'] {
      margin-block-end: 0;
      margin-block-start: 0;
      margin-inline-end: 10px;
      margin-inline-start: 0;

      > div {
        margin: 0;
        width: 16px !important; // Important is required here due to built in styles.
      }
    }

    [class*='checkboxCss']::after {
      background-color: black;
      border-color: black;
    }

    [class*='contentCss'] {
      overflow: hidden;
    }

    [class*='containerCss']:not([isdisabled]) {
      &:hover::before,
      &:has(:focus-visible)::before,
      &:active::before {
        background-color: rgba(0, 0, 0, 0.1);
      }
    }
  }
`
