import React, { useEffect, useState } from 'react'
import { i18n } from '@fs/zion-locale'
import { css, cx } from '@linaria/core'
import { ControlZoomIn, ControlZoomOut } from '@fs/zion-icon'
import { rawDayColors } from '@fs/zion-ui/quarks-authorized-use-only'
import { ControlPosition } from 'azure-maps-control'

import CustomControl from './CustomControl'
import useMap from '../../shared/hooks/useMap'

const buttonsClassName = css`
  align-items: center;
  box-shadow: rgba(0, 0, 0, 0.3) 0px 1px 4px -1px;
  display: flex;
  flex-direction: column;
  justify-content: center;
  margin: 10px;
`

const buttonClassName = css`
  background-color: ${rawDayColors.gray['00']};
  border: none;
  color: #666666;
  padding: 2px;
  pointer-events: auto;
  position: relative;
  z-index: 3;

  &:disabled {
    color: #d1d1d1;
    cursor: default;
  }

  &:hover:not(:disabled) {
    color: #333333;
  }

  + button::before {
    background-color: #e6e6e6;
    block-size: 1px;
    content: '';
    display: block;
    inline-size: 30px;
    inset-block-start: 0;
    inset-inline-start: 50%;
    position: absolute;
    transform: translateX(-50%);
  }
`

const zoomInClassName = css`
  border-radius: 2px 2px 0 0;
`

const zoomOutClassName = css`
  border-radius: 0 0 2px 2px;
`

const ZOOM_DURATION_MS = 300
const ZOOM_TYPE = 'ease'

export default function ZoomControl() {
  const { map, nonInteractive } = useMap()
  const [zoomInDisabled, setZoomInDisabled] = useState(false)
  const [zoomOutDisabled, setZoomOutDisabled] = useState(false)

  // Handle zoom changes to enable/disable buttons
  useEffect(() => {
    function zoomChangeHandler() {
      const camera = map.getCamera()

      setZoomInDisabled(camera.zoom >= camera.maxZoom)
      setZoomOutDisabled(camera.zoom <= camera.minZoom)
    }

    if (map) {
      map.events.add('zoomend', zoomChangeHandler)
      zoomChangeHandler() // Initial check to set button states
    }

    return () => {
      map?.events.remove('zoomend', zoomChangeHandler)
    }
  }, [map])

  if (nonInteractive) {
    return null
  }

  function zoomIn() {
    map.setCamera({ duration: ZOOM_DURATION_MS, type: ZOOM_TYPE, zoom: map.getCamera().zoom + 1 })
  }

  function zoomOut() {
    map.setCamera({ duration: ZOOM_DURATION_MS, type: ZOOM_TYPE, zoom: map.getCamera().zoom - 1 })
  }

  return (
    <CustomControl position={ControlPosition.TopRight}>
      <div className={buttonsClassName}>
        <button
          aria-label={i18n.t('map.zoom-control.zoom-in', 'Zoom in')}
          className={cx(buttonClassName, zoomInClassName)}
          disabled={zoomInDisabled}
          onClick={zoomIn}
          title={i18n.t('map.zoom-control.zoom-in', 'Zoom in')}
          type="button"
        >
          <ControlZoomIn size="md" />
        </button>
        <button
          aria-label={i18n.t('map.zoom-control.zoom-out', 'Zoom out')}
          className={cx(buttonClassName, zoomOutClassName)}
          disabled={zoomOutDisabled}
          onClick={zoomOut}
          title={i18n.t('map.zoom-control.zoom-out', 'Zoom out')}
          type="button"
        >
          <ControlZoomOut size="md" />
        </button>
      </div>
    </CustomControl>
  )
}
