import React, { useEffect, useState } from 'react'
import { i18n } from '@fs/zion-locale'
import { Button, Checkbox, ListItem, MenuOverlay, Row } from '@fs/zion-ui'
import { ControlPosition } from 'azure-maps-control'

import CustomControl from './CustomControl'
import useMap from '../../shared/hooks/useMap'
import menuClassName from '../../shared/controls/menuClassName'

export default function MapTypeControl({ initialMapTypeId = 'roadmap' }) {
  const { map, nonInteractive } = useMap()
  const [mapTypeId, setMapTypeId] = useState('road')
  const [showTerrain, setShowTerrain] = useState(false)
  const [showLabels, setShowLabels] = useState(true)

  useEffect(() => {
    if (map) {
      // Note: blank is blank, no need to convert it.
      let convertedInitialMapTypeId = initialMapTypeId
      if (initialMapTypeId === 'hybrid') {
        convertedInitialMapTypeId = 'satellite_road_labels'
      } else if (initialMapTypeId === 'roadmap') {
        convertedInitialMapTypeId = 'road'
      } else if (initialMapTypeId === 'satellite') {
        convertedInitialMapTypeId = 'satellite'
      } else if (initialMapTypeId === 'terrain') {
        convertedInitialMapTypeId = 'road_shaded_relief'
      }

      setMapTypeId(convertedInitialMapTypeId)
      setShowTerrain(convertedInitialMapTypeId === 'road_shaded_relief')
      setShowLabels(convertedInitialMapTypeId !== 'satellite')

      if (map.ready) {
        map.setStyle({ style: convertedInitialMapTypeId })
      } else {
        map.events.addOnce('load', () => {
          map.setStyle({ style: convertedInitialMapTypeId })
        })
      }
    }
  }, [initialMapTypeId, map])

  if (nonInteractive || mapTypeId === 'blank') {
    return null
  }

  let index = mapTypeId.startsWith('road') ? 1 : 2
  if (mapTypeId === 'blank') {
    index = 0
  }

  return (
    <CustomControl position={ControlPosition.TopLeft}>
      <Row className={menuClassName} data-selected-button-index={index} guttersX="none">
        <MenuOverlay
          aria-label={i18n.t('map.map-type-control.street', 'Show street map')}
          menuButton={
            <Button title={i18n.t('map.map-type-control.street', 'Show street map')}>
              {i18n.t('map.map-type-control.map', 'Map')}
            </Button>
          }
          onClick={() => {
            if (showTerrain) {
              map.setStyle({ style: 'road_shaded_relief' })
              setMapTypeId('road_shaded_relief')
            } else {
              map.setStyle({ style: 'road' })
              setMapTypeId('road')
            }
          }}
        >
          <ListItem
            onClick={(event) => {
              event.stopPropagation()

              if (showTerrain) {
                map.setStyle({ style: 'road' })
                setMapTypeId('road')
              } else {
                map.setStyle({ style: 'road_shaded_relief' })
                setMapTypeId('road_shaded_relief')
              }

              setShowTerrain(!showTerrain)
            }}
            primaryText={i18n.t('map.map-type-control.terrain', 'Terrain')}
            startElement={
              <Checkbox
                checked={showTerrain}
                aria-label={i18n.t('map.map-type-control.terrain', 'Terrain')}
                name={i18n.t('map.map-type-control.terrain', 'Terrain')}
                onChange={() => {
                  // The onChange handler is required but we do not need to do anything here.
                }}
              />
            }
            title={i18n.t('map.map-type-control.street-terrain', 'Show street map with terrain')}
          />
        </MenuOverlay>
        <MenuOverlay
          aria-label={i18n.t('map.map-type-control.imagery', 'Show satellite imagery')}
          menuButton={
            <Button title={i18n.t('map.map-type-control.imagery', 'Show satellite imagery')}>
              {i18n.t('map.map-type-control.satellite', 'Satellite')}
            </Button>
          }
          onClick={() => {
            if (showLabels) {
              map.setStyle({ style: 'satellite_road_labels' })
              setMapTypeId('satellite_road_labels')
            } else {
              map.setStyle({ style: 'satellite' })
              setMapTypeId('satellite')
            }
          }}
        >
          <ListItem
            onClick={(event) => {
              event.stopPropagation()

              if (showLabels) {
                map.setStyle({ style: 'satellite' })
                setMapTypeId('satellite')
              } else {
                map.setStyle({ style: 'satellite_road_labels' })
                setMapTypeId('satellite_road_labels')
              }

              setShowLabels(!showLabels)
            }}
            primaryText={i18n.t('map.map-type-control.labels', 'Labels')}
            startElement={
              <Checkbox
                checked={showLabels}
                aria-label={i18n.t('map.map-type-control.labels', 'Labels')}
                name={i18n.t('map.map-type-control.labels', 'Labels')}
                onChange={() => {
                  // The onChange handler is required but we do not need to do anything here.
                }}
              />
            }
            title={i18n.t('map.map-type-control.imagery-names', 'Show imagery with street names')}
          />
        </MenuOverlay>
      </Row>
    </CustomControl>
  )
}
