import React, { useRef, useState } from 'react'
import { css } from '@linaria/core'
import { Person } from '@fs/zion-icon'
import { i18n } from '@fs/zion-locale'
import { rawDayColors } from '@fs/zion-ui/quarks-authorized-use-only'
import { ControlPosition } from 'azure-maps-control'

import CustomControl from './CustomControl'
import UserLocation from '../../shared/controls/UserLocation'
import useMap from '../../shared/hooks/useMap'

const buttonClassName = css`
  background-color: ${rawDayColors.gray['00']};
  border: none;
  border-radius: 2px;
  box-shadow: rgba(0, 0, 0, 0.3) 0px 1px 4px -1px;
  color: #666666;
  inset-block-start: 0;
  inset-inline-end: 120px;
  margin: 10px;
  padding: 8px;
  pointer-events: auto;
  position: absolute;
  z-index: 3;

  &:hover {
    color: #333333;
  }
`

export default function UserLocationControl() {
  const controlRef = useRef(null)
  const [userLocationClickHandler, setUserLocationClickHandler] = useState()
  const { nonInteractive } = useMap()

  if (nonInteractive) {
    return null
  }

  if (controlRef.current === null) {
    controlRef.current = document.createElement('div')
  }

  function handleOnClick() {
    userLocationClickHandler?.()
  }

  return (
    <>
      <CustomControl position={ControlPosition.TopRight}>
        <button
          aria-label={i18n.t('map.your-location.action', 'Your location')}
          className={buttonClassName}
          onClick={handleOnClick}
          title={i18n.t('map.your-location.action', 'Your location')}
          type="button"
        >
          <Person />
        </button>
      </CustomControl>
      <UserLocation setClickHandler={setUserLocationClickHandler} />
    </>
  )
}
