import React, { useRef } from 'react'
import { css } from '@linaria/core'
import { ControlTarget } from '@fs/zion-icon'
import { i18n } from '@fs/zion-locale'
import { rawDayColors } from '@fs/zion-ui/quarks-authorized-use-only'
import { data, ControlPosition } from 'azure-maps-control'

import { useChildrenBounds } from '../../../../components/Map/hooks/useChildrenBounds'
import useMap from '../../shared/hooks/useMap'
import CustomControl from './CustomControl'

const BoundingBox = data.BoundingBox

const buttonClassName = css`
  background-color: ${rawDayColors.gray['00']};
  border: none;
  border-radius: 2px;
  box-shadow: rgba(0, 0, 0, 0.3) 0px 1px 4px -1px;
  color: #666666;
  inset-block-start: 0;
  inset-inline-end: 60px;
  margin: 10px;
  padding: 8px;
  pointer-events: auto;
  position: absolute;
  z-index: 3;

  &:hover {
    color: #333333;
  }
`

const LARGEST_MARKER_SIZE_PX = 64

export default function ResetViewControl() {
  const controlRef = useRef(null)
  const { initialLatitude, initialLongitude, initialZoom, map, nonInteractive, zoomPan } = useMap()
  const childrenBounds = useChildrenBounds()

  if (nonInteractive) {
    return null
  }

  if (controlRef.current === null) {
    controlRef.current = document.createElement('div')
  }

  function handleOnClick() {
    if (childrenBounds.bounds) {
      const boundingBox = BoundingBox.fromEdges(
        childrenBounds.bounds.west,
        childrenBounds.bounds.south,
        childrenBounds.bounds.east,
        childrenBounds.bounds.north
      )

      map.setCamera({
        bounds: boundingBox,
        padding: LARGEST_MARKER_SIZE_PX,
      })
    } else if (childrenBounds.optimalZoom !== undefined && childrenBounds.centroidLocation) {
      zoomPan({
        latitude: childrenBounds.centroidLocation.latitude,
        longitude: childrenBounds.centroidLocation.longitude,
        zoom: childrenBounds.optimalZoom,
      })
    } else {
      zoomPan({
        latitude: initialLatitude,
        longitude: initialLongitude,
        zoom: initialZoom,
      })
    }
  }

  return (
    <CustomControl position={ControlPosition.TopRight}>
      <button
        aria-label={i18n.t('map.reset-view.action', 'Reset view')}
        className={buttonClassName}
        onClick={handleOnClick}
        title={i18n.t('map.reset-view.action', 'Reset view')}
        type="button"
      >
        <ControlTarget />
      </button>
    </CustomControl>
  )
}
